// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Escrow {
    enum State { Created, Funded, Delivered, Disputed, Resolved, Refunded }

    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public amount;
    State public state;

    modifier inState(State expected) {
        require(state == expected, "Invalid state");
        _;
    }

    constructor(address _seller, address _arbiter) {
        buyer = msg.sender;
        seller = _seller;
        arbiter = _arbiter;
        state = State.Created;
    }

    function fund() external payable inState(State.Created) {
        require(msg.sender == buyer, "Not buyer");
        require(msg.value > 0, "No value");
        amount = msg.value;
        state = State.Funded;
    }

    function markDelivered() external inState(State.Funded) {
        require(msg.sender == seller, "Not seller");
        state = State.Delivered;
    }

    function confirmReceipt() external inState(State.Delivered) {
        require(msg.sender == buyer, "Not buyer");
        state = State.Resolved;
        payable(seller).transfer(amount);
    }

    function dispute() external inState(State.Delivered) {
        require(msg.sender == buyer, "Not buyer");
        state = State.Disputed;
    }

    function resolve(bool refundBuyer) external inState(State.Disputed) {
        require(msg.sender == arbiter, "Not arbiter");
        if (refundBuyer) {
            state = State.Refunded;
            payable(buyer).transfer(amount);
        } else {
            state = State.Resolved;
            payable(seller).transfer(amount);
        }
    }
}

