// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SecureVault {
    mapping(address => uint256) public shares;
    uint256 public totalShares;
    uint256 public totalAssets;
    bool private locked;

    modifier nonReentrant() {
        require(!locked, "Reentrancy");
        locked = true;
        _;
        locked = false;
    }

    function deposit() external payable nonReentrant {
        uint256 sharesToMint = totalShares == 0
            ? msg.value
            : (msg.value * totalShares) / totalAssets;
        shares[msg.sender] += sharesToMint;
        totalShares += sharesToMint;
        totalAssets += msg.value;
    }

    function withdraw(uint256 _shares) external nonReentrant {
        require(shares[msg.sender] >= _shares, "Insufficient shares");
        uint256 amount = (_shares * totalAssets) / totalShares;

        // EFFECT: Update state BEFORE external call
        shares[msg.sender] -= _shares;
        totalShares -= _shares;
        totalAssets -= amount;

        // INTERACTION: External call AFTER state update
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "Transfer failed");
    }
}
